import{_ as e,o,c as a,ag as i}from"./chunks/framework.YaIgwL5o.js";const x=JSON.parse('{"title":"Text & Typography","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/text-typography.md","filePath":"tutorials/text-typography.md"}'),r={name:"tutorials/text-typography.md"};function n(l,t,s,h,p,d){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="text-typography" tabindex="-1">Text &amp; Typography <a class="header-anchor" href="#text-typography" aria-label="Permalink to &quot;Text &amp; Typography&quot;">​</a></h1><p>This tutorial covers the text tools: inserting text boxes, formatting, inline math, and text paths.</p><h2 id="inserting-a-text-box" tabindex="-1">Inserting a text box <a class="header-anchor" href="#inserting-a-text-box" aria-label="Permalink to &quot;Inserting a text box&quot;">​</a></h2><ol><li>Click the <strong>Text</strong> button in the toolbar (or press <code>T</code>).</li><li>A text element appears on the slide. Double-click it to start typing.</li><li>Press <code>Escape</code> when you&#39;re done editing.</li></ol><h2 id="formatting-text" tabindex="-1">Formatting text <a class="header-anchor" href="#formatting-text" aria-label="Permalink to &quot;Formatting text&quot;">​</a></h2><p>With text selected inside a text box, use the toolbar to:</p><ul><li><strong>Bold</strong> / <strong>Italic</strong> / <strong>Underline</strong> / <strong>Strikethrough</strong></li><li><strong>Font family</strong> — choose from 30+ built-in fonts (Barlow, Inter, Playfair Display, Computer Modern, etc.)</li><li><strong>Font size</strong> — type a custom size or pick from the dropdown</li><li><strong>Text color</strong> — click the color swatch to open the picker</li><li><strong>Alignment</strong> — left, center, or right</li><li><strong>Lists</strong> — ordered or unordered</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can mix fonts, sizes, and colors within the same text box by selecting individual words and applying different styles.</p></div><h2 id="inline-math" tabindex="-1">Inline math <a class="header-anchor" href="#inline-math" aria-label="Permalink to &quot;Inline math&quot;">​</a></h2><p>You can insert LaTeX math expressions directly inside running text.</p><ol><li>Double-click a text box to enter edit mode.</li><li>Type a LaTeX expression between dollar signs: <code>$E = mc^2$</code></li><li>Press <code>Space</code> after the closing <code>$</code> — the expression renders inline.</li><li>To edit the math, click on the rendered expression. A math editor appears in the right panel.</li></ol><h3 id="example-output" tabindex="-1">Example output <a class="header-anchor" href="#example-output" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/inline-math.html" style="width:100%;height:140px;border:none;"></iframe></div><h2 id="text-on-a-path" tabindex="-1">Text on a path <a class="header-anchor" href="#text-on-a-path" aria-label="Permalink to &quot;Text on a path&quot;">​</a></h2><p>Text Path lets you place text along a curved line.</p><ol><li>Click the <strong>Text Path</strong> button in the toolbar (the curved-T icon).</li><li>A text path element appears with default text on a sine wave.</li><li>Double-click to edit the text content.</li><li>In the right panel, adjust the <strong>path type</strong> (wave, arc, circle) and <strong>amplitude</strong>.</li></ol>',16)])])}const g=e(r,[["render",n]]);export{x as __pageData,g as default};
